tool.command:
mkdir out ; 

## Rename all input files to correct extensions
mv "$scan" "$scan.element_identifier" ;  
mv "$predicted" "$predicted.element_identifier" ; 
mv "$found" "$found.element_identifier" ; 

#set $options = ""

#if $mask:
	#set $options = $options + " --integration-mask-file " + str($mask) + " " 
#end if
#if $erosion:
	#set $options = $options + " --integration-mask-relative-erostion-radius " + str($erostion) + " " 
#end if
#if $kiVec:
	#set $options = $options + " --ki-vec " + str($kiVec) + " " 
#end if

python -m subhkl.io.parser integrator "$scan.element_identifier" $instrument "$predicted.element_identifier" out/integrator.h5 --integration-method $method --found-peaks-file $found --region-growth-distance-threshold $distance --region-growth-minimum-intensity $intensity --region-growth-minimum-sigma $sigma --region-growth-maximum-pixel-radius $radius --peak-center-box-size $boxSize --peak-smoothing-window-size $windowSize --peak-minimum-pixels $pixels --peak-minimum-signal-to-noise $signal --peak-pixel-outlier-threshold $threshold --create-visualizations --show-progress $options ;
